const fs = require("node:fs");
const path = require("node:path");
const { execSync } = require("node:child_process");

/**
 * Pre-install verification script.
 * Ensures the .npmrc is correctly configured to prevent dependency confusion
 * before any packages are installed.
 */

const REQUIRED_SCOPE = "@company";
const EXPECTED_PRIVATE_REGISTRY = "https://npm.internal.company.com/";

function fatal(message) {
  console.error(`\n[SECURITY] FATAL: ${message}`);
  console.error("[SECURITY] Aborting install to prevent potential dependency confusion.\n");
  process.exit(1);
}

function warn(message) {
  console.warn(`[SECURITY] WARNING: ${message}`);
}

function info(message) {
  console.log(`[SECURITY] ${message}`);
}

function verifyNpmrcExists() {
  const npmrcPath = path.join(__dirname, "..", ".npmrc");
  if (!fs.existsSync(npmrcPath)) {
    fatal(
      ".npmrc file is missing. The project requires an .npmrc that maps " +
      `${REQUIRED_SCOPE} to the private registry.`
    );
  }
  return npmrcPath;
}

function verifyNpmrcContent(npmrcPath) {
  const content = fs.readFileSync(npmrcPath, "utf8");
  const lines = content.split("\n").map((line) => line.trim());

  // Check that the @company scope is explicitly mapped to the private registry
  const scopeRegistryPattern = new RegExp(
    `^${REQUIRED_SCOPE.replace("/", "\\/")}:registry\\s*=\\s*${EXPECTED_PRIVATE_REGISTRY.replace(/[.*+?^${}()|[\]\\]/g, "\\$&")}`,
    "i"
  );

  const hasScopeMapping = lines.some((line) => scopeRegistryPattern.test(line));
  if (!hasScopeMapping) {
    fatal(
      `Missing or incorrect scope-to-registry mapping. ` +
      `Expected: ${REQUIRED_SCOPE}:registry=${EXPECTED_PRIVATE_REGISTRY}`
    );
  }

  // Ensure no hardcoded tokens are present
  const hardcodedTokenPattern = /^\s*\/\/[^:]+\/:_authToken\s*=\s*(?!\$\{).+/;
  const hasHardcodedToken = lines.some(
    (line) => !line.startsWith("#") && hardcodedTokenPattern.test(line)
  );
  if (hasHardcodedToken) {
    fatal(
      "Hardcoded authentication token detected in .npmrc. " +
      "Use environment variables (e.g., ${NPM_INTERNAL_TOKEN}) instead."
    );
  }

  // Warn if strict-ssl is disabled
  const strictSslDisabled = lines.some(
    (line) => !line.startsWith("#") && /^strict-ssl\s*=\s*false/i.test(line)
  );
  if (strictSslDisabled) {
    fatal("strict-ssl is set to false. TLS must be enforced for all registry connections.");
  }

  info(".npmrc content validation passed.");
}

function verifyRegistryResolution() {
  try {
    const result = execSync(`npm config get ${REQUIRED_SCOPE}:registry`, {
      encoding: "utf8",
      timeout: 10000,
    }).trim();

    if (result !== EXPECTED_PRIVATE_REGISTRY && result !== EXPECTED_PRIVATE_REGISTRY.replace(/\/$/, "")) {
      fatal(
        `${REQUIRED_SCOPE} scope resolves to unexpected registry: "${result}". ` +
        `Expected: "${EXPECTED_PRIVATE_REGISTRY}"`
      );
    }

    info(`${REQUIRED_SCOPE} scope correctly resolves to ${result}`);
  } catch (error) {
    fatal(`Failed to verify registry resolution for ${REQUIRED_SCOPE}: ${error.message}`);
  }
}

function verifyAuthTokenEnvVar() {
  // We only warn here because CI systems inject tokens at build time,
  // and local development may use `npm login` session tokens.
  if (!process.env.NPM_INTERNAL_TOKEN) {
    warn(
      "NPM_INTERNAL_TOKEN environment variable is not set. " +
      "Ensure it is available at install time for private registry authentication."
    );
  } else {
    info("NPM_INTERNAL_TOKEN environment variable is set.");
  }
}

function verifyPackageJsonIntegrity() {
  const packageJsonPath = path.join(__dirname, "..", "package.json");
  const packageJson = JSON.parse(fs.readFileSync(packageJsonPath, "utf8"));

  // Ensure the package is marked as private
  if (!packageJson.private) {
    fatal(
      'package.json must have "private": true to prevent accidental publishing.'
    );
  }

  // Verify all @company scoped dependencies are present and no unexpected scopes exist
  const allDeps = {
    ...packageJson.dependencies,
    ...packageJson.devDependencies,
  };

  const companyPackages = Object.keys(allDeps).filter((dep) =>
    dep.startsWith(`${REQUIRED_SCOPE}/`)
  );

  if (companyPackages.length === 0) {
    warn("No @company scoped packages found in dependencies.");
  } else {
    info(`Found ${companyPackages.length} @company scoped package(s): ${companyPackages.join(", ")}`);
  }

  // Check for suspicious version ranges that could indicate tampering
  for (const [pkg, version] of Object.entries(allDeps)) {
    if (typeof version === "string") {
      // Flag dependencies using URLs or git references (potential supply chain risk)
      if (
        version.startsWith("http://") ||
        version.startsWith("https://") ||
        version.startsWith("git://") ||
        version.startsWith("git+") ||
        version.startsWith("github:")
      ) {
        warn(
          `Package "${pkg}" uses a URL/git dependency: "${version}". ` +
          "Verify this is intentional and from a trusted source."
        );
      }
    }
  }

  info("package.json integrity checks passed.");
}

// Run all verifications
info("Running pre-install security verification...\n");

const npmrcPath = verifyNpmrcExists();
verifyNpmrcContent(npmrcPath);
verifyRegistryResolution();
verifyAuthTokenEnvVar();
verifyPackageJsonIntegrity();

info("\nAll pre-install security checks passed. Proceeding with install.\n");